mapper.select:
SELECT a.company_name, a.company_abbr, count(1) as 'receivableContractNum', SUM(COALESCE(b.breach_amount, 0) - COALESCE(b.receive_breach_amount, 0)) AS 'receivableBreachAmount', sum( COALESCE(b.total_amount, 0) - COALESCE(b.dealed_amount, 0) + COALESCE(b.breach_amount, 0) - COALESCE(b.receive_breach_amount, 0) ) as 'receivableBalance' FROM t_bs_company_dcsx a left join t_ctr_contract b on b.our_company_name = a.company_name
b.contract_type = 'S' and b.enterprise_id = 44 and b.contract_status!= 'C' and b.business_type ='ZY-BB' AND b.match_credit_flg = TRUE and a.enable_flg = '1' and ( COALESCE(b.total_amount, 0)+ COALESCE(b.interest_amount, 0) - COALESCE(b.dealed_amount, 0) ) >0
and b.dept_id = #{deptId}
AND DATE_FORMAT(b.contract_time, '%Y-%m-%d') >= #{contractTimeBegin}
AND DATE_FORMAT(b.contract_time, '%Y-%m-%d') <= #{contractTimeEnd}
and a.company_name in
#{companyNameList[${index}],jdbcType=VARCHAR}
GROUP BY a.company_name, a.company_abbr order by sum( COALESCE(b.total_amount, 0) - COALESCE(b.dealed_amount, 0) + COALESCE(b.breach_amount, 0) - COALESCE(b.receive_breach_amount, 0) ) desc
